import { Autumn } from 'autumn-js';

const app = express();
app.use(express.json());

const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
});

// POST /workspaces — Create a workspace entity in Autumn
app.post('/workspaces', async (req, res) => {
  try {
    const { workspaceId, customerId, name } = req.body;

    if (!workspaceId || !customerId) {
      return res.status(400).json({ error: 'workspaceId and customerId are required' });
    }

    const entity = await autumn.entities.create({
      customerId,
      entityId: workspaceId,
      featureId: 'workspaces',
      name: name || workspaceId,
    });

    res.status(201).json({
      workspaceId: entity.id,
      customerId: entity.customerId,
      name: entity.name,
      featureId: entity.featureId,
      createdAt: entity.createdAt,
    });
  } catch (err) {
    console.error('Error creating workspace:', err);
    res.status(500).json({ error: err.message || 'Failed to create workspace' });
  }
});

