  try {
    const { workspaceId, customerId, name } = req.body;

    if (!workspaceId || !customerId) {
      return res.status(400).json({ error: 'workspaceId and customerId are required' });
    }

    const entity = await autumn.entities.create({
      customerId,
      entityId: workspaceId,
      featureId: 'workspaces',
      name: name || workspaceId,
    });

    res.status(201).json({
      workspaceId: entity.id,
      customerId: entity.customerId,
      name: entity.name,
      featureId: entity.featureId,
      createdAt: entity.createdAt,
    });
  } catch (err) {
    console.error('Error creating workspace:', err);
    res.status(500).json({ error: err.message || 'Failed to create workspace' });
  }
});

// POST /workspaces/:workspaceId/use-credits — Check and consume workspace credits
app.post('/workspaces/:workspaceId/use-credits', async (req, res) => {
  try {
    const { workspaceId } = req.params;
    const { customerId, featureId = 'credits', value = 1 } = req.body;

    if (!customerId) {
      return res.status(400).json({ error: 'customerId is required' });
    }

    // Check if workspace has sufficient balance
    const checkResult = await autumn.check({
      customerId,
      featureId,
      entityId: workspaceId,
      requiredBalance: value,
    });

    if (!checkResult.allowed) {
      return res.status(402).json({
        allowed: false,
        message: 'Insufficient credits',
        balance: checkResult.balance,
      });
    }

    // Consume the credits by tracking usage
    const trackResult = await autumn.track({
      customerId,
      featureId,
      entityId: workspaceId,
      value,
    });

    res.json({
      allowed: true,
      workspaceId,
      featureId,
      consumed: value,
      balance: trackResult.balance,
    });
  } catch (err) {
    console.error('Error using workspace credits:', err);
    res.status(500).json({ error: err.message || 'Failed to use credits' });
  }
});

